const raw = items[0].json.content[0].text.trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  // tenta extrair JSON de dentro do texto caso Claude tenha adicionado texto
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : { nome: 'PROJETO SEM NOME', prior: 'Nula', solic: '', prazo: '', nota: raw };
}

const wppData = $('Receber Evolution API').first().json.body.data;
const msgId = wppData.key?.id || ('wpp_' + Date.now());

return [{
  json: {
    id:    'wpp_' + msgId,
    who:   wppData.pushName || 'WhatsApp',
    solic: parsed.solic || wppData.pushName || '',
    nome:  (parsed.nome || 'PROJETO SEM NOME').toUpperCase().trim(),
    prior: parsed.prior || 'Nula',
    prazo: parsed.prazo || '',
    nota:  parsed.nota  || '',
    msg:   wppData.message?.conversation || '',
    time:  new Date().toLocaleString('pt-BR', { timeZone: 'America/Bahia' })
  }
}];

